import React from 'react';
import { Link } from 'react-router-dom';
import './AboutStats.css';

const PORTRAIT_IMG = 'https://framerusercontent.com/images/LG47yzJKYPaE9iSMjClLZQLV0Iw.jpg?width=2160&height=1440';

const stats = [
  { value: '15', suffix: '+', label: 'Years of Experience' },
  { value: '100', suffix: '+', label: 'Projects Completed' },
  { value: '97', suffix: '%', label: 'Client Satisfaction Rate' },
  { value: '75', suffix: '%', label: 'Conversion Rate Improvement' },
];

// Exact images from scarlet.framer.media
const boldLines = [
  {
    parts: [
      { type: 'text', text: 'Bold Ideas', muted: false },
      { type: 'img', src: 'https://framerusercontent.com/images/hpK2jiBaOZYg5CRERfR8Du1A4.jpg?width=2160&height=1440', rotate: 6 },
      { type: 'text', text: 'Striking Designs', muted: true },
    ],
  },
  {
    parts: [
      { type: 'img', src: 'https://framerusercontent.com/images/rwxqhSPLCEUd9f042FJNbwEnA.jpg?width=2160&height=1440', rotate: -6 },
      { type: 'text', text: 'Precision in Every Pixel', muted: false },
    ],
  },
  {
    parts: [
      { type: 'text', text: 'Design Without', muted: true },
      { type: 'img', src: 'https://framerusercontent.com/images/xYIjrYqPZg27nDGjg3uDQa6GE.jpg?width=2160&height=1440', rotate: 6 },
      { type: 'text', text: 'Limits', muted: false },
    ],
  },
];

export default function AboutStats() {
  return (
    <section className="about-stats">
      <div className="as-container">

        {/* ── Row 1: Label + Heading ── */}
        <div className="about-heading-row">
          <div className="about-label-col">
            <span className="section-label">
              <span className="label-dot" />
              About us
            </span>
          </div>
          <div className="about-heading-col">
            <h2 className="about-heading">
              We blend creativity with precision, transforming ideas into{' '}
              <span className="heading-muted">
                impactful brand identities, sleek user interfaces, and standout digital assets.
              </span>
            </h2>
          </div>
        </div>

        {/* ── Row 2: Stats + Portrait ── */}
        <div className="about-body-row">
          <div className="stats-col">
            {stats.map((s) => (
              <div key={s.label} className="stat-card">
                <div className="stat-number">
                  <span className="stat-value">{s.value}</span>
                  <span className="stat-suffix">{s.suffix}</span>
                </div>
                <p className="stat-label">{s.label}</p>
              </div>
            ))}
            <div className="cta-card">
              <Link to="/about" className="cta-link">
                <span>More about us</span>
                <span className="cta-arrow">↗</span>
              </Link>
            </div>
          </div>

          <div className="portrait-col">
            <div className="portrait-wrapper">
              <img src={PORTRAIT_IMG} alt="About us" className="portrait-img" />
            </div>
          </div>
        </div>

      </div>

      {/* ── Bold Ideas Section — full width with side padding ── */}
      <div className="bold-ideas-section">
        <hr className="bold-ideas-rule" />
        <div className="bold-ideas-inner">
          {boldLines.map((line, li) => (
            <div className="bi-line" key={li}>
              {line.parts.map((part, pi) =>
                part.type === 'text' ? (
                  <span
                    key={pi}
                    className={`bi-text ${part.muted ? 'bi-muted' : 'bi-dark'}`}
                  >
                    {part.text}
                  </span>
                ) : (
                  <div
                    key={pi}
                    className="bi-img-wrap"
                    style={{ transform: `rotate(${part.rotate}deg)` }}
                  >
                    <img src={part.src} alt="" />
                  </div>
                )
              )}
            </div>
          ))}
        </div>
        <hr className="bold-ideas-rule" />
      </div>

    </section>
  );
}
